import{_ as e,o as a,c as i,a0 as d}from"./chunks/framework.CRI-85sq.js";const u=JSON.parse('{"title":"NanaSQLite セキュリティ／性能監査レポート（2026-07-22）","description":"","frontmatter":{},"headers":[],"relativePath":"security_audit.md","filePath":"security_audit.md"}'),s={name:"security_audit.md"};function r(l,t,h,n,o,c){return a(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="nanasqlite-セキュリティ-性能監査レポート-2026-07-22" tabindex="-1">NanaSQLite セキュリティ／性能監査レポート（2026-07-22） <a class="header-anchor" href="#nanasqlite-セキュリティ-性能監査レポート-2026-07-22" aria-label="Permalink to &quot;NanaSQLite セキュリティ／性能監査レポート（2026-07-22）&quot;">​</a></h1><p><strong>対象:</strong> NanaSQLite v1.6.0（現行 HEAD）<br><strong>範囲:</strong> <code>src/nanasqlite/</code> 全体、SQL 構築経路、暗号化、バックアップ／復元、Async/V2 境界、および回帰テスト群</p><h2 id="結論" tabindex="-1">結論 <a class="header-anchor" href="#結論" aria-label="Permalink to &quot;結論&quot;">​</a></h2><p>現行 HEAD では、ライブラリが受け取るべき入力を経由して再現可能な新規 Critical / High 脆弱性は確認されませんでした。</p><p>既知の識別子・列型・式・PRAGMA に関する SQL injection の回帰は、テストと実装レビューでブロックされていることを確認しました。なお、この結論はアプリケーションが SQL 文字列やファイルパスを未検証の利用者入力として直接渡さないことを前提にします。</p><table tabindex="0"><thead><tr><th>区分</th><th style="text-align:right;">Critical</th><th style="text-align:right;">High</th><th style="text-align:right;">Medium</th><th style="text-align:right;">Low</th><th>状態</th></tr></thead><tbody><tr><td>新規の再現可能な脆弱性</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td>確認されず</td></tr><tr><td>設計上の信頼境界</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td style="text-align:right;">0</td><td style="text-align:right;">3</td><td>運用上の注意</td></tr></tbody></table><h2 id="実施した確認" tabindex="-1">実施した確認 <a class="header-anchor" href="#実施した確認" aria-label="Permalink to &quot;実施した確認&quot;">​</a></h2><ul><li>SQL が動的に組み立てられる全経路をレビュー</li><li>AES-GCM / ChaCha20-Poly1305、バックアップ／復元、Async/V2 の境界をレビュー</li><li><code>python -m tox -e lint,type</code> — PASS</li><li><code>python -m pytest tests -x -q</code> — <strong>1051 passed, 12 skipped</strong></li></ul><h2 id="確認済みの防御" tabindex="-1">確認済みの防御 <a class="header-anchor" href="#確認済みの防御" aria-label="Permalink to &quot;確認済みの防御&quot;">​</a></h2><table tabindex="0"><thead><tr><th>攻撃面</th><th>現行の防御</th></tr></thead><tbody><tr><td>識別子</td><td><code>_sanitize_identifier()</code> による許可リスト検証と引用</td></tr><tr><td>列型</td><td>文字種・括弧深さの検証で列定義の割り込みを拒否</td></tr><tr><td>SQL 式</td><td>危険な SQL、サブクエリ系キーワード、未許可関数を検査</td></tr><tr><td>PRAGMA</td><td>読取／書込の許可リスト</td></tr><tr><td>暗号化値</td><td>ランダム nonce の AEAD。復号失敗時に平文へフォールバックしない</td></tr><tr><td>バックアップ／復元</td><td>integrity check、一時ファイルからの原子的置換、WAL/SHM の隔離</td></tr></tbody></table><h2 id="信頼境界と運用上の注意" tabindex="-1">信頼境界と運用上の注意 <a class="header-anchor" href="#信頼境界と運用上の注意" aria-label="Permalink to &quot;信頼境界と運用上の注意&quot;">​</a></h2><h3 id="sql-文字列-api" tabindex="-1">SQL 文字列 API <a class="header-anchor" href="#sql-文字列-api" aria-label="Permalink to &quot;SQL 文字列 API&quot;">​</a></h3><p><code>execute()</code> / <code>execute_many()</code> は任意 SQL を実行する管理者向け API です。<code>query()</code> の <code>where</code>、非識別子の <code>columns</code>、<code>order_by</code> も SQL 式を受け取ります。外部入力を文字列連結して渡さず、値は必ずプレースホルダーで渡してください。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db.query(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;users&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;email = ?&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">parameters</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(email,))</span></span></code></pre></div><p><code>strict_sql_validation=True</code> は追加の防御層ですが、任意 SQL を安全な検索 DSL に変換する機能ではありません。</p><h3 id="バックアップ-復元のパス" tabindex="-1">バックアップ／復元のパス <a class="header-anchor" href="#バックアップ-復元のパス" aria-label="Permalink to &quot;バックアップ／復元のパス&quot;">​</a></h3><p>Web API 等から受け取ったパスを直接 <code>backup()</code> / <code>restore()</code> に渡さず、アプリケーション側で許可ディレクトリを解決・検証してください。</p><h3 id="高負荷時の非同期投入" tabindex="-1">高負荷時の非同期投入 <a class="header-anchor" href="#高負荷時の非同期投入" aria-label="Permalink to &quot;高負荷時の非同期投入&quot;">​</a></h3><p>サービス境界では semaphore 等で同時実行数を制限してください。無制限の投入は待ち行列とメモリ使用量を増加させます。</p><h2 id="継続方針" tabindex="-1">継続方針 <a class="header-anchor" href="#継続方針" aria-label="Permalink to &quot;継続方針&quot;">​</a></h2><ol><li>値は必ずバインドし、識別子は <code>_sanitize_identifier()</code> を経由させる。</li><li>SQL 構築 API の変更時は注入回帰テストを追加する。</li><li>リリース前に lint・型検査・全回帰テストを実行する。</li><li>依存パッケージの CVE は本レポートの対象外として、別途依存関係監査を行う。</li></ol>',21)])])}const g=e(s,[["render",r]]);export{u as __pageData,g as default};
